// Parse CSV from webhook body
// Accepts: POST with Content-Type: text/plain or application/json {csv: "..."}
const input = $input.first().json;
const body = input.body;

let csvText = '';
if (typeof body === 'string') {
  csvText = body;
} else if (body && body.csv) {
  csvText = body.csv;
} else {
  throw new Error('Send CSV as plain text body or JSON: {"csv": "id,value,label
1,100,test"}');
}

const lines = csvText.trim().split('
').filter(l => l.trim());
if (lines.length < 2) throw new Error('CSV must have header row + at least 1 data row');

const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
const rows = [];
for (let i = 1; i < lines.length; i++) {
  const vals = lines[i].split(',').map(v => v.trim());
  const row = {};
  headers.forEach((h, idx) => row[h] = vals[idx] ?? '');
  rows.push({ json: row });
}
return rows;

// Validate all rows in a single pass
const rows = $input.all();
const valid = [];
const invalid = [];
const seen = new Set();

for (const row of rows) {
  const d = row.json;
  const rowNum = d._rowIndex;
  const errors = [];

  if (!d.id || String(d.id).trim() === '')   errors.push('missing id');
  if (d.value === null || d.value === '' || isNaN(parseFloat(d.value))) errors.push('value not numeric');
  if (!d.label || String(d.label).trim() === '') errors.push('missing label');
  if (d.id && seen.has(String(d.id))) errors.push('duplicate id');

  if (errors.length > 0) {
    invalid.push({ row: rowNum, id: d.id ?? null, errors });
  } else {
    seen.add(String(d.id));
    valid.push({
      json: {
        id: String(d.id).trim(),
        value: parseFloat(d.value),
        label: String(d.label).trim(),
        source: 'csv-upload',
        ingested_at: $now.toISO()
      }
    });
  }
}

if (valid.length > 0) {
  valid[0].json._summary = {
    total: rows.length,
    passed: valid.length,
    failed: invalid.length,
    invalidRows: invalid
  };
}

if (valid.length === 0) {
  throw new Error(`All ${rows.length} rows failed validation: ` + JSON.stringify(invalid));
}

return valid;

