// Pull summary from first item and build report
const items = $input.all();
const summary = items[0]?.json?._summary ?? {
  total: items.length,
  passed: items.length,
  failed: 0,
  invalidRows: []
};

return [{
  json: {
    report: {
      inserted: summary.passed,
      skipped: summary.failed,
      total: summary.total,
      invalid_rows: summary.invalidRows,
      timestamp: $now.toISO()
    }
  }
}];
